window.__QUIZ_DATA__=[{"id":"objective>Physics>2010>1","subject":"Physics","year":"2010","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following properties of a long steel bar would alter if the bar were melted, recast into a cube and allowed to cool to its original temperature?","images":[],"options":{"A":"Density","B":"Volume","C":"Specific heat capacity","D":"Electrical resistance"},"answer":"D","explanation":"The electrical resistance of a material depends on its shape and size, as well as its resistivity. When the steel bar is melted and recast into a cube, its shape and size change, which would alter its electrical resistance. The other properties like density, volume, and specific heat capacity are intrinsic properties of the material and would not change with the change in shape or size.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>2","subject":"Physics","year":"2010","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS","question":"Which of the following instruments is the best for measuring the diameter of a thin constantan wire?","images":[],"options":{"A":"Callipers","B":"Metre rule","C":"Micrometer screw gauge","D":"Vernier callipers"},"answer":"C","explanation":"The micrometer screw gauge can be used to measure the diameter of a thin constantan wire. This is possible because of its accuracy (0.01mm).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>3","subject":"Physics","year":"2010","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"What is the density of a fuel relative density 0.72?  [Density of water = 1000kgm-3]","images":[],"options":{"A":"72kg m-3","B":"720kg m-3","C":"7200kg m-3","D":"72000kg m-3"},"answer":"B","explanation":"Given: (1) the relative density of the fuel = 0.72  (2) the density of water = 1000kgm-3  Recall:Therelativedensityofasubstance=Density of the substanceDensity of water  \u22340.72=Density of the substance1000  Density of the substance = 72kgm-3","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>4","subject":"Physics","year":"2010","type":"Objective","topic":"MOTION : TYPES OF MOTION","question":"The types of motion which a cylindrical drum rolling down an inclined plane undergoes are","images":[],"options":{"A":"circular and translational","B":"rotational and translational","C":"rotational and circular","D":"rectilinear and circular"},"answer":"B","explanation":"The circumference of the drum is undergoing rotational motion while the centre undergoes translational motion.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>5","subject":"Physics","year":"2010","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : FIRST LAW","question":"Which of the following statements about a moving particle is correct?","images":[],"options":{"A":"If the resultant force acting on the particle is zero, then it is in dynamic equilibrium","B":"If the resultant force acting on the particle is greater than zero, then it is moving with a uniform velocity","C":"The rate of change of its momentum with time takes place in a direction opposite to that of its motion","D":"The particle failing freely covers equal distances in equal time intervals"},"answer":"A","explanation":"A particle is in dynamic equilibrium if the resultant force acting on it is zero. This means that the sum of all forces acting on the particle is zero, resulting in no acceleration or change in velocity. Therefore, the particle can either be at rest or moving with a constant velocity.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>6","subject":"Physics","year":"2010","type":"Objective","topic":"MOTION : SOLID FRICTION","question":"Which of the following statements about static friction is correct? It","images":[],"options":{"A":"is independent of the nature of surfaces in contact","B":"depends on the area of surfaces in contact","C":"depends on the relative motion between the surfaces in contact","D":"depends on the weight of the moving body"},"answer":"D","explanation":"Static friction is the friction that needs to be overcome to start moving an object. It depends on the weight of the moving body because the heavier the object, the more force is needed to overcome the static friction and start moving the object. This is due to the fact that friction is a force that opposes motion, and it is proportional to the normal force (which is the weight of the object in this case).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>7","subject":"Physics","year":"2010","type":"Objective","topic":"MOTION : RELATIVE MOTION","question":"Two cars X and Y travelling in opposite directions along the same highway at uniform velocities 110kmh-1 and 90kmh-1 respectively pass each other at a certain point. The velocity of X relative to Y at the time they pass each other is","images":[],"options":{"A":"200kmh-1","B":"100kmh-1","C":"40kmh-1","D":"20kmh-1"},"answer":"A","explanation":"The relative velocity of the two cars X and Y as at the time they pass each other = The sum of their velocities  \u2234 Relative velocity = 110 + 90 = 200kmh-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>8","subject":"Physics","year":"2010","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF SPEED","question":"The average speed of an object is determined by dividing the sum of its initial and final speeds by two only when the acceleration is","images":[],"options":{"A":"changing","B":"uniform","C":"increasing","D":"decreasing"},"answer":"B","explanation":"The average speed of an object is determined by dividing the sum of its initial and final speeds by two only when the acceleration is uniform. This is because when acceleration is uniform, the object's speed changes at a constant rate, so the average speed is simply the average of the initial and final speeds.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>9","subject":"Physics","year":"2010","type":"Objective","topic":"PROJECTILE MOTION :","question":"A body is projected horizontally from the top of a cliff 45m above the ground. If the body lands at a distance 30m from the foot of the cliff. Calculate the speed of projection.  [g = 10ms-2]","images":[],"options":{"A":"10ms-1","B":"15ms-1","C":"20ms-1","D":"30ms-1"},"answer":"A","explanation":"Given: The height, h of projection 45m  The range, R of projection = 30m. The velocity, U of projection = ?  Recall: R = UT ......(1)  T=&radic;2Hg&nbsp;......(2)  \u2234R=u&radic;2\u00d7Hg&nbsp;  30=u&radic;9010&nbsp;  30 = u*&radic;9&nbsp;  30 = u \u00d7 3  30 = 3u  u = 10ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>10","subject":"Physics","year":"2010","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"Which of the following statements best describes a rigid body? A body which","images":[],"options":{"A":"is not easily deformed","B":"when deformed remains its shape","C":"is brittle","D":"when deformed remains deformed"},"answer":"A","explanation":"A rigid body is a body that is not easily deformed. This means that it can withstand forces applied to it without changing its shape or size. This is different from a brittle body, which can break or crack easily, or a body that remains deformed after a force is applied, which would indicate that it is not rigid.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>11","subject":"Physics","year":"2010","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"A simple harmonic oscillator has a period of 0.02s and amplitude of 0.25m. Calculate the speed in ms-1 at the centre of the oscillation.","images":[],"options":{"A":"1.25\u03c0","B":"25.00\u03c0","C":"100.00\u03c0","D":"400.00\u03c0"},"answer":"B","explanation":"Given: (1) the period, T = 0.02s  (2) the amplitude, A = 0.25m   Recall: Frequency,F=1T......(i)  Speed,V=\u03c9A......(ii)  Angular speed, \u03c9 = 2\u03c0f ......(iii)  \u2234F=10.02=50Hz  \u03c9 = 2\u03c0 \u00d7 50 = 100\u03c0  V = 100\u03c0 \u00d7 0.25  V = 2.5\u03c0","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>12","subject":"Physics","year":"2010","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A vertical string, suspended from a fixed point and having a small mass attached to the free end is set into oscillations. Which of the following statements about the system are correct?  I. The potential energy of the mass is a minimum at the middle of the swing.  II. Its kinetic energy is a maximum at the middle of the swing.  III. The sum of the potential and kinetic energies is constant throughout the swing.","images":[],"options":{"A":"I, II and III","B":"I and II only","C":"II and III only","D":"I and III only"},"answer":"C","explanation":"It kinetic energy is a maximum at the middle of the swing. The sum of P.E and K.E is constant throughout.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>13","subject":"Physics","year":"2010","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A moving body of mass 25.0kg undergoes a uniform retardation of 20.0m-2. Calculate the magnitude of the retarding force.","images":[],"options":{"A":"1.25N","B":"8.00N","C":"45.00N","D":"500.00N"},"answer":"D","explanation":"Given: The mass, m of the body = 25.0kg  The retardation = 200ms-2  The magnitude of the retarding force, F = ?  Recall: F = mass \u00d7 retardation  F = 25 \u00d7 (20) = 500N","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>14","subject":"Physics","year":"2010","type":"Objective","topic":"ENERGY : WORLD ENERGY RESOURCES","question":"Which of the following sources of energy is/are exhaustible?  I. Solar  II. Fossil fuel  III. Tidal power","images":[],"options":{"A":"II only","B":"III only","C":"I and II only","D":"II and III only"},"answer":"A","explanation":"Exhaustible energy sources are those that are finite and will eventually run out. Fossil fuels, such as coal, oil, and natural gas, are examples of exhaustible energy sources because they take millions of years to form. On the other hand, solar energy and tidal power are renewable energy sources because they are replenished naturally and regularly. Therefore, only statement II is correct.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>15","subject":"Physics","year":"2010","type":"Objective","topic":"MACHINES :","question":"A machine is said to be a third class lever when the","images":[],"options":{"A":"load is between the fulcrum and effort","B":"fulcrum is between the effort and load","C":"effort is between the fulcrum and load","D":"fulcrum is directly below the load"},"answer":"C","explanation":"The third class lever is such that the effort is found between the fulcrum and the load. e.g Wheel barrow.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>16","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"A thermometer records 680 mmHg at steam point and 440 mm at ice point. The temperature it records at 380 mmHg is","images":[],"options":{"A":"-25\u00b0C","B":"-20\u00b0C","C":"20\u00b0C","D":"25\u00b0C"},"answer":"A","explanation":"Given: (1) The reading at steam point = 680mmHg.  (2) The reading at ice point = 440mmHg  (3) The temperature, \u03b8 when it reads 380mmHg = ?  \u2234x - 0100 - x =380 - 440680 - 380  x100 - x=-60300  x100 - x=-15  5x = x - 100  4x = -100  x = -25\u00b0c","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>17","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The advantages of the thermoelectric thermometer include the following characteristics except that it","images":[],"options":{"A":"can measures rapidly changing temperatures","B":"can measure high and low temperatures","C":"can measure temperature almost at a point","D":"is fairly sensitive"},"answer":"D","explanation":"The fact it is fairly sensitive is not an advantage.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>18","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"In a thermos flask, heat loss by radiation is minimized by the","images":[],"options":{"A":"silvered surfaces","B":"vacuum within the double walls","C":"plastic stopper","D":"cork support"},"answer":"A","explanation":"In a thermos flask, heat loss by radiation is minimized by the silvered surfaces. The silvered surfaces reflect the heat radiation back into the flask, preventing it from escaping. This is a principle of thermal radiation, where shiny or white surfaces are good reflectors of heat.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>19","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The pressure P, volume V and absolute temperature T of a given mass of an ideal gas, change simultaneously. Which of the following equations is correct about the gas?","images":[],"options":{"A":"PV=constantT","B":"PT=constant","C":"PV=constantT","D":"1T=constantPV"},"answer":"D","explanation":"The product of pressure and the quotient of volume and temperature is constant for and ideal gas","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>20","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"Specific heat capacity 26.4Jkg-1k-1 of a body means that when 26.4J of heat energy is supplied to a body of","images":[],"options":{"A":"mass 1000 kg, the temperature rises by 1K","B":"mass 1kg, the temperature rises by 1000K","C":"mass 1kg, the temperature rises by 1K","D":"mass 1000kg, the temperature rises by 1000K"},"answer":"C","explanation":"The specific heat capacity = 264Jkg-1k-1. This is the heat energy supplied to a body of mass, 1 kg when the temperature is raised b 1K.  \u2234 Specific heat capacity of 264Jkg-1k-1 means when 264J of heat energy is supplied to a body of mass, 1 kg, the temperature is raised by 1K.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>21","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"An electric drill rated 400W is used to drill a hole in copper of mass 400g in 20s. Calculate the rise in temperature if all the heat produced is absorbed by the copper.  [Specific heat capacity of copper = 400Jkg-1k-1]","images":[],"options":{"A":"100\u00b0C","B":"75\u00b0C","C":"50\u00b0C","D":"45\u00b0C"},"answer":"C","explanation":"Given: (1) The power rating, P of the drill = 400W  (2) The mass of copper = 400g  (3) The time taken, t = 205  (4) SHC of copper = 400Jkg-1k-1.  N:B: Heat energy lost by the drill = Heat gained by copper   \u2234 Electrical power \u00d7 Time = mass \u00d7 SHC \u00d7 Temperature rise.  = 400 \u00d7 20 = 0.4 \u00d7 400 \u00d7 Temperature rise  8000 = 160 \u00d7 Temperature rise  \u2234 Temperature rise = 50\u00b0C or 50K","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>22","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : LATENT HEAT","question":"A solid of mass 0.5kg initially at 50\u00b0C melts at 60\u00b0C. Calculate the quantity of heat required to melt it completely.  [Specific heat capacity of the solid = 1.0 kJkg-1k-1]  [Specific latent of heat of fusion of solid = 2.0kJkg-1]","images":[],"options":{"A":"1500J","B":"10000J","C":"10500J","D":"15000J"},"answer":"C","explanation":"Given: (1) mass, m of the solid = 0.5kg  (2) Initial temperature, \u03b81 = 50\u00b0c  (3) Final temperature, \u03b82 = 60\u00b0c  (4) SHC of the solid = 2.0KJKg-1k-1  (5) Specific latent heat of fusion = 1.0 kJkg-1.  Quantity of Heat = mL + mc\u0394\u03b8  Q = 0.5 \u00d7 1 + 0.5 \u00d7 2 \u00d7 10   = (0.5 + 10)kJ = 10.5kJ = 10,500J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>23","subject":"Physics","year":"2010","type":"Objective","topic":"HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT","question":"Dew point is not affected by","images":[],"options":{"A":"temperature","B":"wind","C":"the amount of water vapour in the atmosphere","D":"atmospheric pressure"},"answer":"B","explanation":"Dew point is the temperature at which air becomes saturated with water vapor, after which the water vapor begins to condense into liquid water. It is affected by the temperature, the amount of water vapor in the atmosphere, and the atmospheric pressure. However, it is not affected by wind.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>24","subject":"Physics","year":"2010","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"A certain wave has a speed of 20ms-1. If the frequency of the wave is 0.25Hz, calculate the distance between successive crests of the wave.","images":[],"options":{"A":"5.0m","B":"40.0m","C":"50.0m","D":"80.0m"},"answer":"D","explanation":"Given: (1) the speed, v = 20ms-1  (2) the frequency, f of the wave = 0.25Hz  (3) the wavelength, \u03bb is unknown  Recall: v = f\u03bb  20 = 0.25\u03bb  \u03bb = 80.0m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>25","subject":"Physics","year":"2010","type":"Objective","topic":"PROPERTIES OF WAVES : DIFFRACTION","question":"The ability of a wave to spread around corners is called","images":[],"options":{"A":"polarisation","B":"dispersion","C":"diffraction","D":"reflection"},"answer":"C","explanation":"The ability of a wave to spread around corners is called diffraction. Diffraction is a wave phenomenon that describes the ability of waves to bend around obstacles and spread out after passing through a narrow opening.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>26","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The following devices use plane mirrors in their operations, except","images":[],"options":{"A":"periscope","B":"sextant","C":"kaleidoscope","D":"binoculars"},"answer":"D","explanation":"Binoculars do not use plane mirrors in their operations. Instead, they use a series of lenses to magnify distant objects. On the other hand, periscopes, sextants, and kaleidoscopes all use plane mirrors in their operations.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>27","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"When an object is placed at the principal focus of a concave mirror, the location of the image formed is","images":[],"options":{"A":"between principal focus and pole","B":"between principal focus and centre of curvature","C":"at infinity","D":"at centre of curvature"},"answer":"C","explanation":"When an object is placed at the principal focus of a concave mirror, the image formed is always at infinity.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>28","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"From the diagram above, the correct equation for the refractive index n of the medium is","images":["data:image/png;base64,"],"options":{"A":"n = tani","B":"n=sinisin90\u00b0","C":"n=sinicos(90\u00b0 - i)","D":"n = sin90\u00b0"},"answer":"A","explanation":"refractiveindex(n)=sin isin r  where r = 180 - (90 + i)    \u2192 r = 90 - i    since sin(90 - i) = cos i    \u2234refractiveindex(n)=sin icos i=tani","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>29","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light travels from air to water. The refractive index of water is given by the expression","images":[],"options":{"A":"velocity in watervelocity in air","B":"sine of angle of refractionsine of angle of incidence","C":"apparent depthreal depth","D":"wavelength in air  wavelength in water"},"answer":"D","explanation":"Given: The two media concerned; air and water.  It should be noted that, refracted index, n can be expressed in many ways.  1.n=Velocity in media 1  Velocity in media 2  2.n=Wavelength in media 1  Wavelength in media 2  3.n=Sine of angle of incidencesine of angle of refraction","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>30","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A lens that is thinner at the middle and thicker at the edges is","images":[],"options":{"A":"diverging","B":"converging","C":"plano-convex","D":"converging meniscus"},"answer":"A","explanation":"A lens that is thinner at the middle and thicker at the edges is a diverging lens. This is because it spreads out light rays that are incident on it, causing them to diverge or spread out.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>31","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following electromagnetic waves has the longest wavelength?","images":[],"options":{"A":"Radio waves","B":"Gamma rays","C":"Infrared waves","D":"Ultraviolet rays"},"answer":"A","explanation":"The electromagnetic spectrum is the range of all types of EM radiation. Radiation is energy that travels and spreads out as it goes \u2013 the visible light that comes from a lamp in your house and the radio waves that come from a radio station are two types of electromagnetic radiation. The other types of EM radiation that make up the electromagnetic spectrum are microwaves, infrared light, ultraviolet light, X-rays and gamma-rays. Among these, Radio waves have the longest wavelength.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>32","subject":"Physics","year":"2010","type":"Objective","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"The amplitude of a sound wave determines its","images":[],"options":{"A":"frequency","B":"quality","C":"loudness","D":"pitch"},"answer":"C","explanation":"In a sound wave, the amplitude is related to the level of energy it carries. Sound waves with greater amplitudes move particles of air, or other media through which they are traveling, with greater intensity and thus, we perceive the sound wave as being louder. So, the amplitude of a sound wave determines its loudness.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>33","subject":"Physics","year":"2010","type":"Objective","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"As the air column of length L in an air pipe decreases, the frequency of the stationary wave emitted.","images":[],"options":{"A":"decreases","B":"increases","C":"varies as D2","D":"varies as &radic;L&nbsp;"},"answer":"B","explanation":"Frequency,F\u03b11\u221aLength  As the length, L reduces/decrease, the frequency F will increase.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>34","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"A positively charged glass rod is placed near the cap of a positively chaged electroscope. The divergence of the leaf is observed to","images":[],"options":{"A":"decrease","B":"increase","C":"remain the same","D":"increase and collapse immediately"},"answer":"B","explanation":"When the positively charged glass rod is placed near the cap of a positively charged electroscope, the divergence of the leaf is increased.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>35","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Capacitors are used in the following devices, except","images":[],"options":{"A":"water pumping machines","B":"ceiling fans","C":"electric irons","D":"television sets"},"answer":"A","explanation":"Capacitors are used in electrical devices to store electrical energy temporarily. They are commonly found in ceiling fans, electric irons, and television sets where they help in smoothing out the flow of electricity or blocking direct current while allowing alternating current to pass. However, water pumping machines typically do not use capacitors.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>36","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Use the diagram beside to answer this question.        Calculate the current, I.","images":["data:image/png;base64,"],"options":{"A":"0.60A","B":"0.97A","C":"1.03A","D":"5.00A"},"answer":"B","explanation":"Given: The circuit diagram  Current, I = ?  Electromotive force, e.m.f = 12v  Load=4 \u00d7 64 + 6+10=2.4+10=12.4\u03a9  Recall: V = IR  \u2234I=VR=1212.4=0.97A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>37","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Use the diagram beside to answer this question.      Determine the potential difference, V across the parallel resistors.","images":["data:image/png;base64,"],"options":{"A":"2.0V","B":"2.3V","C":"3.0V","D":"9.7V"},"answer":"B","explanation":"Req of the parallel connection = 6\u00d746+4\\frac{6\u00d74}{6+4}6+46\u00d74\u200b = 2.4 &#937;  Recall: V = IR  \u2234 V = 0.97 \u00d7 2.4 = 2.3V","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>38","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"A galvanometer of internal resistance 50\u03a9 and full scale deflection of 20mA is converted into a voltmeter by connecting a resistor of resistance 1950\u03a9 in series to it. Calculate the maximum voltage that can be read by the voltmeter.","images":[],"options":{"A":"20V","B":"30V","C":"38V","D":"40V"},"answer":"D","explanation":"Given: The current, I = 20 \u00d7 10-3A = 0.02A  Internal Resistance, r = R1 = 50\u03a9  Load = 1950\u03a9  Maximum voltage, V = IR1 + IR2   = 0.02 (50 + 1950)   = 0.02(2000)   = 40V","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>39","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"In the wiring of houses, the fuse is connected to the wire coloured","images":[],"options":{"A":"blue","B":"brown","C":"yellow","D":"yellow and green"},"answer":"B","explanation":"In the wiring of houses, the fuse is connected to the live wire which is usually brown in color. The fuse is a safety device that protects the electrical circuit by breaking the circuit when there is an overload. The live wire is the wire that carries current from the power source to the appliance.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>40","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"Which of the following factors does not affect the electric resistance of a wire?","images":[],"options":{"A":"Length","B":"Mass","C":"Temperature","D":"Cross-sectional area"},"answer":"B","explanation":"The electric resistance of a wire is affected by its length, temperature, and cross-sectional area but not its mass. The resistance of a wire increases with its length and temperature and decreases with its cross-sectional area. This is because resistance is a measure of how much a material opposes the flow of electric current, and these factors affect how easily current can flow through the wire.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>41","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"Which of the following factors will increase the sensitivity of a moving coil meter?","images":[],"options":{"A":"Strong spring","B":"Low number of turns","C":"Small area of coil","D":"Soft iron core"},"answer":"D","explanation":"The sensitivity of a moving coil meter will be increased if the construction is composed of soft iron core.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>42","subject":"Physics","year":"2010","type":"Objective","topic":"MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS","question":"In other to prevent bar magnets from losing their strength, they are stored with keepers such that the two bars are placed with","images":[],"options":{"A":"like poles facing each other and the keepers placed at their ends","B":"like poles facing each other and the keepers placed between them","C":"unlike poles facing each other and the keepers placed at their ends","D":"unlike poles facing each other and the keepers placed between them."},"answer":"C","explanation":"Keepers are materials in which magnets are stored, so as to preserve their magnetic properties. Unlike poles of the magnet usually face each other with the keepers placed at their ends.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>43","subject":"Physics","year":"2010","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : RESONANCE","question":"The resonant frequency of an a.c circuit is 1000kHz. If each of the capacitance and inductance in the circuit is reduced by 50% and no other changes are made, the resonant frequency will become","images":[],"options":{"A":"250kHz","B":"750kHz","C":"1000kHz","D":"2000kHz"},"answer":"D","explanation":"Given: Fo (Resonant frequency) = 1000kHz.  Recall: Fo=12\u03c0&radic;LC&nbsp;  L2=L12  C2=C12  F1&radic;L1C1&nbsp; = F2&radic;L2C2&nbsp;  F1F2=&radic;L2C2L1C1&nbsp;  F1F2=&radic;L1/2 \u00d7 C1/2 L1C1&nbsp;  F1F2=&radic;L1C14\u00d71L1C1&nbsp;  F1F2=&radic;14&nbsp;  F1F2=12  F1 \u00d7 2 = F2  \u2234 F2 = 2F1 = 2 \u00d7 1000  = 2000KHz","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>44","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTROMAGNETIC FIELD : INDUCTANCE","question":"The energy, E stored in an inductor of inductance L when current I passes through it is given by the equation.","images":[],"options":{"A":"E=12LI2","B":"E = LI2","C":"E=12LI","D":"E=12L2I"},"answer":"A","explanation":"The energy stored in an inductor is given by the formula E = 1/2 LI2, where L is the inductance and I is the current. This formula comes from the work done in establishing the current in the inductor. The work done against the back emf (electromotive force) in establishing the current is stored as magnetic potential energy.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>45","subject":"Physics","year":"2010","type":"Objective","topic":"ELECTROMAGNETIC FIELD : EDDY CURRENTS","question":"Eddy currents can be reduced by","images":[],"options":{"A":"using coil of high resistance","B":"winding the coil on a soft iron core","C":"creating holes in the metal plates","D":"using coil of low resistance"},"answer":"C","explanation":"Eddy currents are circulating currents induced in the metal body when it is subjected to a changing magnetic field. These currents cause energy loss due to heating effect. Eddy currents can be reduced by creating holes in the metal plates, which breaks the path of the eddy currents and thus reduces their magnitude.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>46","subject":"Physics","year":"2010","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"An electron moves with a speed of 2.0 \u00d7 106ms-1 in a straight line. Calculate the wavelength of the electron wave.  [Mass of an electron = 9.1 \u00d7 10-31kg]  [Planck's constant = 6.6 \u00d7 10-34Js]","images":[],"options":{"A":"3.63 \u00d7 10-10 m","B":"6.51 \u00d7 10-9 m","C":"4.24 \u00d7 10-8 m","D":"7.25 \u00d7 10-8 m"},"answer":"C","explanation":"Given: v = 2.0 \u00d7 106ms-1  \u03bb = ?  m = 9.1 \u00d7 10-31kg  h = 6.6 \u00d7 10-34Js  c = 3.0 \u00d7 108ms-1  Recall,   \u03bb=hc1/2 mv2  \u03bb=6.6 \u00d7 10-34 \u00d7 3.0 \u00d7 1081/2 \u00d7 9.1 \u00d7 10-31 \u00d7 (2.0 \u00d7 106)2  \u03bb=6.6\u00d73.00.5\u00d79.1\u00d74\u00d710-34 + 810-31 + 12  \u03bb = 4.243 \u00d7 10-8m  \u03bb = 4.24 \u00d7 10-8m (2d.p)","marks":"1","difficulty":"3"},{"id":"objective>Physics>2010>47","subject":"Physics","year":"2010","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"Oxidation of the filament in a light bulb is prevented by the introduction of","images":[],"options":{"A":"hydrogen","B":"oxygen","C":"argon","D":"mercury vapour"},"answer":"C","explanation":"The filament in a light bulb is usually made of tungsten, which oxidizes and breaks down at high temperatures. To prevent this, the bulb is filled with an inert gas like argon, which does not react with the filament even at high temperatures, thus preventing its oxidation.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2010>48","subject":"Physics","year":"2010","type":"Objective","topic":"STRUCTURE OF THE ATOM : THERMIONIC EMISSION","question":"In a cathode ray tube, the function of the X-plates is to","images":[],"options":{"A":"deflect the electron beam horizontally","B":"deflect the electron beam vertically","C":"reflect the electron beam","D":"generate sinusoidal waves"},"answer":"A","explanation":"In a cathode ray tube, the X-plates are used to deflect the electron beam horizontally. The cathode ray tube works by shooting a beam of electrons (originating from the cathode) towards the anode. The X-plates and Y-plates are used to deflect this beam in the horizontal and vertical directions respectively. This deflection allows the beam to hit different parts of the screen, creating the images we see.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>49","subject":"Physics","year":"2010","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"A nuclide represented as 7032X has a neutron-proton ratio of","images":[],"options":{"A":"0.5","B":"0.8","C":"1.2","D":"1.5"},"answer":"C","explanation":"Given: The nuclide 7032 X. The number of proton = 32 (atomic number) and the number of neutron = (70 - 32) = 38.  \u2234 neutron: Proton ration = 38 : 32  = 19 : 16 = 1 . 2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2010>50","subject":"Physics","year":"2010","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Neutrons are used to induce artificial radioactivity because they","images":[],"options":{"A":"are energetic","B":"have no charge","C":"have no mass","D":"are ionizing"},"answer":"B","explanation":"Neutrons are used to induce artificial radioactivity because they have no charge. This means they can penetrate the nucleus of an atom without being repelled by the positive charge of the protons in the nucleus. Once inside the nucleus, a neutron can cause the atom to become radioactive by upsetting the balance of protons and neutrons.","marks":"1","difficulty":"2"}];